mapper.select:
SELECT h.id, h.course_id, h.student_id, h.images, h.total_questions, h.correct_count, h.score, h.status, h.create_time, c.name AS courseName, s.name AS studentName FROM edu_homework_correction h LEFT JOIN edu_course c ON h.course_id = c.id LEFT JOIN edu_student s ON h.student_id = s.id WHERE h.deleted = 0
AND h.course_id = #{params.courseId}
AND h.student_id = #{params.studentId}
AND s.name LIKE CONCAT('%', #{params.studentName}, '%')
AND h.status = #{params.status}
AND h.course_id IN (SELECT id FROM edu_course WHERE teacher_id = #{params.teacherId} AND deleted = 0)
AND h.student_id IN (SELECT student_id FROM edu_student_group_member WHERE group_id = #{params.groupId})
ORDER BY h.create_time DESC
